-- Create "items" table
CREATE TABLE "items" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "deleted_at" timestamptz NULL, "name" character varying NOT NULL, "description" character varying NOT NULL, PRIMARY KEY ("id"));
-- Create "products" table
CREATE TABLE "products" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "description" character varying NOT NULL, "price" numeric NOT NULL, "currency" character varying NOT NULL DEFAULT 'KZT', "is_active" boolean NOT NULL DEFAULT true, "is_limited" boolean NOT NULL DEFAULT false, "limited_till" timestamptz NULL, "left" bigint NOT NULL DEFAULT 0, "is_unique" boolean NOT NULL DEFAULT false, PRIMARY KEY ("id"));
-- Create "bundles" table
CREATE TABLE "bundles" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "deleted_at" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "amount" double precision NOT NULL DEFAULT 1, "item_id" bigint NOT NULL, "product_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "bundles_items_bundles" FOREIGN KEY ("item_id") REFERENCES "items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "bundles_products_bundles" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "invoices" table
CREATE TABLE "invoices" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "user_id" bigint NOT NULL, "app_id" character varying NOT NULL, "status" character varying NOT NULL DEFAULT 'CREATED', "paid_at" timestamptz NULL, "product_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "invoices_products_invoices" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "consumed_status" table
CREATE TABLE "consumed_status" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "user_id" bigint NOT NULL, "tenant_id" bigint NOT NULL, "app_id" bigint NOT NULL, "consumed" double precision NULL DEFAULT 0, "left" double precision NULL DEFAULT 0, "active_till" timestamptz NULL, "start_from" timestamptz NULL, "invoice_consumed_statuses" bigint NULL, "item_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "consumed_status_invoices_consumed_statuses" FOREIGN KEY ("invoice_consumed_statuses") REFERENCES "invoices" ("id") ON UPDATE NO ACTION ON DELETE SET NULL, CONSTRAINT "consumed_status_items_consumed_statuses" FOREIGN KEY ("item_id") REFERENCES "items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "consumedstatus_user_id_app_id_item_id" to table: "consumed_status"
CREATE INDEX "consumedstatus_user_id_app_id_item_id" ON "consumed_status" ("user_id", "app_id", "item_id");
-- Create "subscription_status" table
CREATE TABLE "subscription_status" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "active_till" timestamptz NULL, "start_from" timestamptz NULL, "invoice_id" bigint NOT NULL, "item_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "subscription_status_invoices_subscription_statuses" FOREIGN KEY ("invoice_id") REFERENCES "invoices" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "subscription_status_items_subscription_statuses" FOREIGN KEY ("item_id") REFERENCES "items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
